mapper.select:
SELECT , COALESCE(fs.management_area, 0) AS management_area, COALESCE(rs.room_count, 0) AS room_count, CASE WHEN COALESCE(rs.room_count, 0) = 0 THEN 0 ELSE ROUND(COALESCE(rs.rented_count, 0) * 100 / rs.room_count, 2) END AS rent_rate, COALESCE(rs.rented_area, 0) AS rented_area FROM ics_building b LEFT JOIN ics_park p ON p.id = b.park_id LEFT JOIN ( SELECT building_id, SUM(COALESCE(area, 0)) AS management_area FROM ics_floor GROUP BY building_id ) fs ON fs.building_id = b.id LEFT JOIN ( SELECT building_id, COUNT(1) AS room_count, SUM(CASE WHEN status = '1' THEN 1 ELSE 0 END) AS rented_count, SUM(CASE WHEN status = '1' THEN COALESCE(area, 0) ELSE 0 END) AS rented_area FROM ics_room GROUP BY building_id ) rs ON rs.building_id = b.id
AND b.id = #{building.id} AND b.park_id = #{building.parkId} AND b.name LIKE CONCAT('%', #{building.name}, '%') AND b.code LIKE CONCAT('%', #{building.code}, '%') AND b.status = #{building.status}
ORDER BY p.name ASC, b.park_id ASC, COALESCE(b.sort_num, 999999) ASC, b.name ASC, b.id ASC
